from collections import defaultdict


class FrequencyTracker:
    def __init__(self):
        self.count = defaultdict(int)
        self.freq_count = defaultdict(int)

    def add(self, number):
        c = self.count[number]
        if c > 0:
            self.freq_count[c] -= 1
        self.count[number] = c + 1
        self.freq_count[c + 1] += 1

    def deleteOne(self, number):
        c = self.count.get(number, 0)
        if c == 0:
            return
        self.freq_count[c] -= 1
        if c - 1 == 0:
            del self.count[number]
        else:
            self.count[number] = c - 1
            self.freq_count[c - 1] += 1

    def hasFrequency(self, frequency):
        return self.freq_count.get(frequency, 0) > 0

