class FrequencyTracker {
    constructor() {
        this.count = new Map();
        this.freqCount = new Map();
    }
    add(number) {
        const c = this.count.get(number) || 0;
        if (c > 0) this.freqCount.set(c, (this.freqCount.get(c) || 0) - 1);
        this.count.set(number, c + 1);
        this.freqCount.set(c + 1, (this.freqCount.get(c + 1) || 0) + 1);
    }
    deleteOne(number) {
        const c = this.count.get(number) || 0;
        if (c === 0) return;
        this.freqCount.set(c, (this.freqCount.get(c) || 0) - 1);
        if (c - 1 === 0) {
            this.count.delete(number);
        } else {
            this.count.set(number, c - 1);
            this.freqCount.set(c - 1, (this.freqCount.get(c - 1) || 0) + 1);
        }
    }
    hasFrequency(frequency) {
        return (this.freqCount.get(frequency) || 0) > 0;
    }
}
